import React, { useState } from 'react';

function AboutPage() {
  // Quiz Data Array (Step 6 concept: Data handling)
  const quizData = [
    {
      question: "What is Cead's favorite flower?",
      options: ["Rose", "Tulip", "Sunflower", "Daisy"],
      answer: 1 // Tulip
    },
    {
      question: "What does the pot represent in 'Cead's Pot'?",
      options: ["A cooking vessel", "The container of the soul/growth", "A garden tool", "Storage"],
      answer: 1
    }
  ];

  // State Management (Step 4)
  const [currentQuestion, setCurrentQuestion] = useState(0);
  const [score, setScore] = useState(0);
  const [showScore, setShowScore] = useState(false);
  const [feedback, setFeedback] = useState("");

  const handleAnswerClick = (index) => {
    if (index === quizData[currentQuestion].answer) {
      setScore(score + 1);
      setFeedback("Correct! ✨");
    } else {
      setFeedback(`Wrong! The correct answer was: ${quizData[currentQuestion].options[quizData[currentQuestion].answer]}`);
    }

    // Move to next question after a short delay
    setTimeout(() => {
      const nextQuestion = currentQuestion + 1;
      if (nextQuestion < quizData.length) {
        setCurrentQuestion(nextQuestion);
        setFeedback("");
      } else {
        setShowScore(true);
      }
    }, 1500);
  };

  return (
    <div className="container">
      <section className="hero">
        <h1>The Keeper of the Personal Gallery</h1>
        <p>
          I use the lens as a mirror to catch the light I often forget I carry. 
          Each frame is a receipt of my own self-love, proving that I am worthy of being seen.
        </p>
      </section>

      {/* About Page Image Grid */}
      <section className="preview-grid">
        <div className="card"><div className="placeholder-img">Photo 1</div></div>
        <div className="card"><div className="placeholder-img">Photo 2</div></div>
      </section>

      {/* React Quiz Component */}
      <section className="quiz-section">
        <h2>Interactive Gallery Quiz</h2>
        <div className="quiz-card">
          {showScore ? (
            <div className="score-section">
              <h3>Quiz Complete!</h3>
              <p>You scored {score} out of {quizData.length}</p>
              <button onClick={() => window.location.reload()} className="btn-submit">Restart Quiz</button>
            </div>
          ) : (
            <>
              <div className="question-section">
                <div className="question-count">
                  <span>Question {currentQuestion + 1}</span>/{quizData.length}
                </div>
                <div className="question-text">{quizData[currentQuestion].question}</div>
              </div>
              <div className="answer-section">
                {quizData[currentQuestion].options.map((option, index) => (
                  <button 
                    key={index} 
                    className="option-button"
                    onClick={() => handleAnswerClick(index)}
                  >
                    {option}
                  </button>
                ))}
              </div>
              {feedback && <p className="feedback-text">{feedback}</p>}
            </>
          )}
        </div>
      </section>
    </div>
  );
}

export default AboutPage;
